mapper.select:
/* Cart.selectActiveCartsBySocialAccountId */
SELECT


WHERE C.SOCIAL_ACCOUNT_ID = #{socialAccountId}
  AND C.DEL_YN = 'N'
  AND C.STATUS = 'A'
ORDER BY C.CRE_TM ASC

/* Cart.selectActiveCartsByGuestTokenId */
SELECT


WHERE C.GUEST_TOKEN_ID = #{guestTokenId}
  AND C.DEL_YN = 'N'
  AND C.STATUS = 'A'
ORDER BY C.CRE_TM ASC

/* Cart.selectActiveCartItemBySocialAccountId */
SELECT


WHERE C.SOCIAL_ACCOUNT_ID = #{socialAccountId}
  AND C.PRODUCT_DET_ID    = #{productDetId}
  AND C.DEL_YN = 'N'
  AND C.STATUS = 'A'
LIMIT 1

/* Cart.selectActiveCartItemByGuestTokenId */
SELECT


WHERE C.GUEST_TOKEN_ID = #{guestTokenId}
  AND C.PRODUCT_DET_ID = #{productDetId}
  AND C.DEL_YN = 'N'
  AND C.STATUS = 'A'
LIMIT 1

/* Cart.selectSellAmtByProductDetId */
SELECT P.SELL_AMT
FROM TB_PRODUCT_DET PD
JOIN TB_PRODUCT P ON P.ID = PD.PRODUCT_ID
WHERE PD.ID = #{productDetId}
LIMIT 1

mapper.update:
/* Cart.updateCartItemQuantity */
UPDATE TB_CART
SET QUANTITY = #{quantity},
    UPT_TM  = NOW()
WHERE ID     = #{cartId}
  AND DEL_YN = 'N'

/* Cart.updateCartItemQuantityById */
UPDATE TB_CART
SET QUANTITY = #{quantity},
    UPT_TM  = NOW()
WHERE ID     = #{cartId}
  AND DEL_YN = 'N'

/* Cart.deleteCartItem */
UPDATE TB_CART
SET DEL_YN = 'Y',
    UPT_TM = NOW()
WHERE ID     = #{cartId}
  AND DEL_YN = 'N'

/* Cart.markDeletedByGuestTokenId */
UPDATE TB_CART
SET DEL_YN = 'Y',
    UPT_TM = NOW()
WHERE GUEST_TOKEN_ID = #{guestTokenId}
  AND DEL_YN = 'N'

/* Cart.updateCartSocialAccountIdByGuestId */
UPDATE TB_CART
SET SOCIAL_ACCOUNT_ID = #{socialAccountId},
    UPT_TM            = NOW()
WHERE GUEST_TOKEN_ID = (
    SELECT ID FROM TB_GUEST_TOKEN
    WHERE GUEST_ID = #{guestId}
    LIMIT 1
)
AND DEL_YN = 'N'

/* Cart.updateCartSocialAccountId */
UPDATE TB_CART
SET SOCIAL_ACCOUNT_ID = #{socialAccountId},
    UPT_TM            = NOW()
WHERE ID = #{id}

/* Cart.updateCartStatus */
UPDATE TB_CART
SET STATUS = #{status},
    UPT_TM = NOW()
WHERE ID = #{id}
